package com.agent.tool.engine.api.impl;  import com.agent.tool.engine.enums.ToolCallStatus; import com.agent.tool.engine.model.ToolCallResult; import org.junit.jupiter.api.DisplayName; import org.junit.jupiter.api.Test;  import java.util.Optional;  import static org.assertj.core.api.Assertions.assertThat;  /**  * {@link ToolCacheImpl} 单元测试。  */ class ToolCacheImplTest {      private final ToolCacheImpl cache = new ToolCacheImpl();      @Test     @DisplayName("未缓存的 hash: lookup 返回 empty")     void should_ReturnEmpty_When_NotCached() {         Optional<ToolCallResult> found = cache.lookup("hash_not_exist");          assertThat(found).isEmpty();         assertThat(cache.size()).isZero();     }      @Test     @DisplayName("缓存写入后命中: 返回副本且 fromCache=true")     void should_ReturnCachedResult_When_Cached() {         ToolCallResult result = new ToolCallResult("tool_1", "output", ToolCallStatus.SUCCESS);         result.setOutputTokens(10);          cache.cache("hash_1", result);          Optional<ToolCallResult> found = cache.lookup("hash_1");         assertThat(found).isPresent();         assertThat(found.get().getToolId()).isEqualTo("tool_1");         assertThat(found.get().getOutput()).isEqualTo("output");         assertThat(found.get().isFromCache()).isTrue();         assertThat(found.get().getStatus()).isEqualTo(ToolCallStatus.SUCCESS);         assertThat(cache.size()).isEqualTo(1);     }      @Test     @DisplayName("空或空白 hash: lookup 和 cache 均跳过")     void should_ReturnEmpty_When_HashIsBlank() {         assertThat(cache.lookup(null)).isEmpty();         assertThat(cache.lookup("  ")).isEmpty();          ToolCallResult result = new ToolCallResult("tool_1", "out", ToolCallStatus.SUCCESS);         cache.cache(null, result);         cache.cache("  ", result);          assertThat(cache.size()).isZero();     }      @Test     @DisplayName("cache null result: 跳过, 不写入")     void should_SkipCache_When_NullResult() {         cache.cache("hash_null", null);          assertThat(cache.size()).isZero();         assertThat(cache.lookup("hash_null")).isEmpty();     }      @Test     @DisplayName("缓存命中返回副本: 修改副本不影响原缓存")     void should_ReturnCopy_When_CacheHit() {         ToolCallResult original = new ToolCallResult("tool_2", "orig", ToolCallStatus.SUCCESS);         cache.cache("hash_2", original);          ToolCallResult copy = cache.lookup("hash_2").orElseThrow();         copy.setOutput("modified");          ToolCallResult second = cache.lookup("hash_2").orElseThrow();         assertThat(second.getOutput()).isEqualTo("orig");     } }